class Solution {
    public int minSteps(int n) {
        if (n == 1) return 0;
        int steps = 0;
        int clipboard = 1;
        int current = 1;
        while (current < n) {
            if (n % current == 0) {
                clipboard = current;
                steps++;
            }
            current += clipboard;
            steps++;
        }
        return steps;
    }
}
```
